   301→    private func createShareIfNeeded() async {
   302→        // Refresh the souvenir object to ensure we have the latest data from Core Data
   303→        context.refresh(souvenir, mergeChanges: true)
   304→
   305→        // Ensure permanent IDs for the souvenir and any related newly created objects
   306→        // before evaluating guards. This prevents transient state from causing false negatives.
   307→        do {
   308→            try await context.perform {
   309→                var objectsNeedingIDs: [NSManagedObject] = [souvenir]
   310→                if let contact = souvenir.primaryContact, contact.objectID.isTemporaryID {
   311→                    objectsNeedingIDs.append(contact)
   312→                }
   313→                for p in souvenir.photosArray where p.objectID.isTemporaryID {
   314→                    objectsNeedingIDs.append(p)
   315→                }
   316→                if !objectsNeedingIDs.isEmpty {
   317→                    try context.obtainPermanentIDs(for: objectsNeedingIDs)
   318→                }
   319→                if context.hasChanges {
   320→                    try context.save()
   321→                }
   322→            }
   323→        } catch {
   324→            // We'll fall back to local share later if needed; do not block UI here.
   325→        }
   326→
   327→        if souvenir.primaryContact == nil || souvenir.photosArray.isEmpty {
   328→            errorMessage = "Please finish adding a photo and primary contact before sharing."
   329→            return
   330→        }
   331→
   332→        // Reuse existing active share
   333→        let activeShares = shareService.activeShares(for: souvenir, in: context)
   334→        if let existing = activeShares.first {
   335→            shareEntity = existing
   336→            didCreateNewShare = false
   337→            if let urlString = existing.cloudKitShareURL, let url = URL(string: urlString) {
   338→                shareURL = url
   339→            } else {
   340→                shareURL = shareService.shareURL(for: existing)
   341→            }
   342→            return
   343→        }
   344→
   345→        // Create new CloudKit share
   346→        isCreatingShare = true
   347→        defer { isCreatingShare = false }
   348→
   349→        do {
   350→            let ckContainer = CKContainer(identifier: "iCloud.ink.kerry.souvenir")
   351→            let userRecordID = try await ckContainer.userRecordID()
   352→            let persistentContainer = PersistenceController.shared.container
   353→            let url = try await shareService.createAndSaveShare(
   354→                for: souvenir,
   355→                container: persistentContainer,
   356→                in: context,
   357→                inviterUserId: userRecordID.recordName
   358→            )
   359→            shareURL = url
   360→            shareEntity = shareService.activeShares(for: souvenir, in: context).first
   361→            didCreateNewShare = true
   362→        } catch CKError.notAuthenticated {
   363→            // User not signed into iCloud — fall back to local token share
   364→            let fallback = shareService.createShare(for: souvenir, in: context)
   365→            shareEntity = fallback
   366→            shareURL = shareService.shareURL(for: fallback)
   367→            try? context.save()
   368→            didCreateNewShare = true
   369→        } catch {
   370→            // CloudKit failure (often due to mirroring/validation) — fall back to local token share
   371→            let fallback = shareService.createShare(for: souvenir, in: context)
   372→            shareEntity = fallback
   373→            shareURL = shareService.shareURL(for: fallback)
   374→            try? context.save()
   375→            didCreateNewShare = true
   376→            errorMessage = "Cloud share unavailable. Using a local share link."
   377→        }
   378→    }
