   408→    private func loadShareImage() {
   409→        guard let favoritePhoto = souvenir.favoritePhoto,
   410→              let assetId = favoritePhoto.assetLocalId else {
   411→            return
   412→        }
   413→
   414→        isLoadingImage = true
   415→
   416→        Task {
   417→            // Race the photo load against a timeout to avoid a perpetual spinner
   418→            let image: UIImage? = await withTaskGroup(of: UIImage?.self) { group in
   419→                // Load image task
   420→                group.addTask {
   421→                    await photoLoader.loadPhoto(
   422→                        assetLocalId: assetId,
   423→                        targetSize: CGSize(width: 600, height: 600),
   424→                        contentMode: .aspectFill
   425→                    )
   426→                }
   427→                // Timeout task (3 seconds)
   428→                group.addTask {
   429→                    try? await Task.sleep(nanoseconds: 3_000_000_000)
   430→                    return nil
   431→                }
   432→                for await result in group {
   433→                    if let result { return result }
   434→                }
   435→                return nil
   436→            }
   437→
   438→            // Generate JPEG data in the background
   439→            let imageData = image?.jpegData(compressionQuality: 0.8)
   440→
   441→            await MainActor.run {
   442→                shareImage = image
   443→                shareImageData = imageData
   444→                isLoadingImage = false
   445→            }
   446→        }
   447→    }
   448→}
