     8→import SwiftUI
     9→import MapKit
    10→import CoreData
    11→import CoreLocation
    12→
    13→struct LocationSearchIsland: View {
    14→    let context: LocationSearchContext
    15→    var searchRegion: MKCoordinateRegion?
    16→    @Binding var islandState: ContactIslandState
    17→    var onDismiss: (() -> Void)?
    18→    var onSelectLocation: ((LocationSearchResult) -> Void)?
    19→    var onSelectSouvenir: ((SouvenirEntity) -> Void)?
    20→    var showsConfirmButton: Bool = false
    21→    var onConfirmLocation: (() async -> Bool)?
    22→
    23→    // Prevent GeometryReader/PresentationDetent churn similar to ContactIsland
    24→    @State private var screenHeight: CGFloat = 0
    25→    @State private var detentCalc = DetentCalculator()
    26→    @State private var cachedDetents = DetentCalculator().detents(for: 0)
    27→
    28→    @State private var query: String = ""
    29→    @State private var results: [LocationSearchResult] = []
    30→    @State private var searchTask: Task<Void, Never>?
    31→    @State private var isSearching: Bool = false
    32→    @State private var suppressNextSearch: Bool = false
    33→    @State private var selectedResult: LocationSearchResult?
    34→    @State private var isDetentSettled: Bool = false
    35→    @State private var isConfirming: Bool = false
    36→    @State private var didConfirmSuccess: Bool = false
    37→
    38→    @FocusState private var isSearchFocused: Bool
    39→
    40→    @FetchRequest private var souvenirs: FetchedResults<SouvenirEntity>
    41→    @FetchRequest private var contextPhotos: FetchedResults<PhotoEntity>
    42→
    43→    private let searchService = LocationSearchService(persistenceController: .shared)
    44→    private typealias Tokens = DesignTokens
    45→
    46→    init(
    47→        context: LocationSearchContext,
    48→        searchRegion: MKCoordinateRegion? = nil,
    49→        islandState: Binding<ContactIslandState>,
    50→        onDismiss: (() -> Void)? = nil,
    51→        onSelectLocation: ((LocationSearchResult) -> Void)? = nil,
    52→        onSelectSouvenir: ((SouvenirEntity) -> Void)? = nil,
    53→        showsConfirmButton: Bool = false,
    54→        onConfirmLocation: (() async -> Bool)? = nil
    55→    ) {
    56→        self.context = context
    57→        self.searchRegion = searchRegion
    58→        self._islandState = islandState
    59→        self.onDismiss = onDismiss
    60→        self.onSelectLocation = onSelectLocation
    61→        self.onSelectSouvenir = onSelectSouvenir
    62→        self.showsConfirmButton = showsConfirmButton
    63→        self.onConfirmLocation = onConfirmLocation
    64→        _souvenirs = FetchRequest(
    65→            sortDescriptors: [
    66→                NSSortDescriptor(keyPath: \SouvenirEntity.updatedAt, ascending: false)
    67→            ],
    68→            predicate: SouvenirEntity.activePredicate,
    69→            animation: .default
    70→        )
    71→        _contextPhotos = FetchRequest(
    72→            sortDescriptors: [],
    73→            predicate: NSPredicate(format: "id == %@", context.photoID as CVarArg)
    74→        )
    75→        // Removed ListAppearance.configureClearBackgrounds()
    76→        // UIKit appearance configuration should not be done during SwiftUI init
    77→        // as it causes observation tracking feedback loops. The appearance is
    78→        // configured once at app launch via .configureListAppearance() modifier.
    79→    }
    80→
    81→    var body: some View {
    82→        VStack(spacing: Tokens.Spacing.medium) {
    83→            islandContent(activeState: islandState)
    84→        }
    85→        .frame(maxWidth: .infinity, maxHeight: .infinity, alignment: .top)
    86→        // Keep sheets translucent by clearing the system background and providing material here.
    87→        .background(Color.clear)
    88→        .background {
    89→            GeometryReader { geo in
    90→                Color.clear.onAppear {
    91→                    let h = geo.size.height
    92→                    if h > screenHeight {
    93→                        screenHeight = h
    94→                    }
    95→                }
    96→                .onChange(of: geo.size.height) { _, newHeight in
    97→                    let newKey = Int(newHeight.rounded())
    98→                    let currentKey = Int(screenHeight.rounded())
    99→                    if newKey > currentKey {
   100→                        screenHeight = newHeight
   101→                    }
   102→                }
   103→            }
   104→        }
   105→        .ignoresSafeArea()
   106→        .onChange(of: screenHeight) { oldHeight, newHeight in
   107→            let oldKey = Int(oldHeight.rounded())
   108→            let newKey = Int(newHeight.rounded())
   109→            if oldKey != newKey {
   110→                cachedDetents = detentCalc.detents(for: newHeight)
   111→            }
   112→        }
   113→        .presentationDetents(
   114→            [cachedDetents.compact, fullSheetDetent],
   115→            selection: detentBinding
   116→        )
   117→        .onChange(of: islandState) { _, _ in
   118→            markUnsettledThenSettle()
   119→        }
   120→        .presentationDragIndicator(.visible)
   121→        .presentationBackground(.ultraThinMaterial)
   122→        .presentationBackgroundInteraction(.enabled)
   123→        .interactiveDismissDisabled(true)
   124→        //.presentationCornerRadius(DesignTokens.ContactIsland.attachedCornerRadius) // removed line
   125→        .onAppear {
   126→            isDetentSettled = false
   127→            if islandState != .fullSheet {
   128→                islandState = .fullSheet
   129→            }
   130→            DispatchQueue.main.asyncAfter(deadline: .now() + 0.2) {
   131→                isDetentSettled = true
   132→                isSearchFocused = true
   133→            }
   134→        }
   135→    }
   136→
   137→    private var fullSheetDetent: PresentationDetent {
   138→        guard screenHeight > 0 else { return cachedDetents.fullSheet }
   139→        let targetHeight = screenHeight * 0.618
   140→        let clamped = min(targetHeight, screenHeight * ContactIslandState.fullSheetMaxRatio)
   141→        return .height(max(clamped, DesignTokens.ContactIsland.fullSheetHeight))
   142→    }
   143→
   144→    private var detentBinding: Binding<PresentationDetent> {
   145→        Binding(
   146→            get: {
   147→                islandState == .compact ? cachedDetents.compact : fullSheetDetent
   148→            },
   149→            set: { newValue in
   150→                islandState = newValue == cachedDetents.compact ? .compact : .fullSheet
   151→            }
   152→        )
   153→    }
