//
//  ViewsLocationSearchIsland.swift
//  souvenir
//
//  Location Search Island
//

import SwiftUI
import MapKit
import CoreData
import CoreLocation

struct LocationSearchIsland: View {
    let context: LocationSearchContext
    var searchRegion: MKCoordinateRegion?
    @Binding var islandState: ContactIslandState
    var onDismiss: (() -> Void)?
    var onSelectLocation: ((LocationSearchResult) -> Void)?
    var onSelectSouvenir: ((SouvenirEntity) -> Void)?
    var showsConfirmButton: Bool = false
    var onConfirmLocation: (() async -> Bool)?

    // Prevent GeometryReader/PresentationDetent churn similar to ContactIsland
    @State private var screenHeight: CGFloat = 0
    @State private var detentCalc = DetentCalculator()
    @State private var cachedDetents = DetentCalculator().detents(for: 0)

    @State private var query: String = ""
    @State private var results: [LocationSearchResult] = []
    @State private var searchTask: Task<Void, Never>?
    @State private var isSearching: Bool = false
    @State private var suppressNextSearch: Bool = false
    @State private var selectedResult: LocationSearchResult?
    @State private var isDetentSettled: Bool = false
    @State private var isConfirming: Bool = false
    @State private var didConfirmSuccess: Bool = false

    @FocusState private var isSearchFocused: Bool

    @FetchRequest private var souvenirs: FetchedResults<SouvenirEntity>
    @FetchRequest private var contextPhotos: FetchedResults<PhotoEntity>

    private let searchService = LocationSearchService(persistenceController: .shared)
    private typealias Tokens = DesignTokens

    init(
        context: LocationSearchContext,
        searchRegion: MKCoordinateRegion? = nil,
        islandState: Binding<ContactIslandState>,
        onDismiss: (() -> Void)? = nil,
        onSelectLocation: ((LocationSearchResult) -> Void)? = nil,
        onSelectSouvenir: ((SouvenirEntity) -> Void)? = nil,
        showsConfirmButton: Bool = false,
        onConfirmLocation: (() async -> Bool)? = nil
    ) {
        self.context = context
        self.searchRegion = searchRegion
        self._islandState = islandState
        self.onDismiss = onDismiss
        self.onSelectLocation = onSelectLocation
        self.onSelectSouvenir = onSelectSouvenir
        self.showsConfirmButton = showsConfirmButton
        self.onConfirmLocation = onConfirmLocation
        _souvenirs = FetchRequest(
            sortDescriptors: [
                NSSortDescriptor(keyPath: \SouvenirEntity.updatedAt, ascending: false)
            ],
            predicate: SouvenirEntity.activePredicate,
            animation: .default
        )
        _contextPhotos = FetchRequest(
            sortDescriptors: [],
            predicate: NSPredicate(format: "id == %@", context.photoID as CVarArg)
        )
        // Removed ListAppearance.configureClearBackgrounds()
        // UIKit appearance configuration should not be done during SwiftUI init
        // as it causes observation tracking feedback loops. The appearance is
        // configured once at app launch via .configureListAppearance() modifier.
    }

    var body: some View {
        VStack(spacing: Tokens.Spacing.medium) {
            islandContent(activeState: islandState)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity, alignment: .top)
        // Keep sheets translucent by clearing the system background and providing material here.
        .background(Color.clear)
        .background {
            GeometryReader { geo in
                Color.clear.onAppear {
                    let h = geo.size.height
                    if h > screenHeight {
                        screenHeight = h
                    }
                }
                .onChange(of: geo.size.height) { _, newHeight in
                    let newKey = Int(newHeight.rounded())
                    let currentKey = Int(screenHeight.rounded())
                    if newKey > currentKey {
                        screenHeight = newHeight
                    }
                }
            }
        }
        .ignoresSafeArea()
        .onChange(of: screenHeight) { oldHeight, newHeight in
            let oldKey = Int(oldHeight.rounded())
            let newKey = Int(newHeight.rounded())
            if oldKey != newKey {
                cachedDetents = detentCalc.detents(for: newHeight)
            }
        }
        .presentationDetents(
            [cachedDetents.compact, fullSheetDetent],
            selection: detentBinding
        )
        .onChange(of: islandState) { _, _ in
            markUnsettledThenSettle()
        }
        .presentationDragIndicator(.visible)
        .presentationBackground(.ultraThinMaterial)
        .presentationBackgroundInteraction(.enabled)
        .interactiveDismissDisabled(true)
        //.presentationCornerRadius(DesignTokens.ContactIsland.attachedCornerRadius) // removed line
        .onAppear {
            isDetentSettled = false
            if islandState != .fullSheet {
                islandState = .fullSheet
            }
            DispatchQueue.main.asyncAfter(deadline: .now() + 0.2) {
                isDetentSettled = true
                isSearchFocused = true
            }
        }
    }

    private var fullSheetDetent: PresentationDetent {
        guard screenHeight > 0 else { return cachedDetents.fullSheet }
        let targetHeight = screenHeight * 0.618
        let clamped = min(targetHeight, screenHeight * ContactIslandState.fullSheetMaxRatio)
        return .height(max(clamped, DesignTokens.ContactIsland.fullSheetHeight))
    }

    private var detentBinding: Binding<PresentationDetent> {
        Binding(
            get: {
                islandState == .compact ? cachedDetents.compact : fullSheetDetent
            },
            set: { newValue in
                islandState = newValue == cachedDetents.compact ? .compact : .fullSheet
            }
        )
    }

    // MARK: - Content

    @ViewBuilder
    private func islandContent(activeState: ContactIslandState) -> some View {
        VStack(spacing: 0) {
            switch activeState {
            case .compact:
                compactContent
            case .fullSheet:
                searchListContent(limit: 7)
            }
        }
        .frame(maxWidth: .infinity)
    }

    private var compactContent: some View {
        VStack(spacing: Tokens.Spacing.small) {
            Spacer(minLength: Tokens.Spacing.medium)
            locationHeaderLabel
                .padding(.horizontal, Tokens.Spacing.large)
            Spacer(minLength: Tokens.Spacing.medium)
        }
        .padding(.vertical, Tokens.Spacing.medium)
    }

    private func searchListContent(limit: Int) -> some View {
        let displayed = Array(results.prefix(limit))
        let trimmedQuery = query.trimmingCharacters(in: .whitespacesAndNewlines)
        let showSouvenirFallback = trimmedQuery.isEmpty && displayed.isEmpty && !isSearching

        return LocationSearchSheet(
            scrollDisabled: islandState != .fullSheet,
            header: {
                inlineSearchField
                    .padding(.vertical, Tokens.Spacing.medium)
                    .padding(.horizontal, Tokens.Spacing.medium)
            },
            results: {
                if showSouvenirFallback {
                    Section {
                        RoundedResultsCard {
                            ForEach(sortedSouvenirs) { souvenir in
                                Button {
                                    selectSouvenir(souvenir)
                                } label: {
                                    HStack(spacing: Tokens.Spacing.medium) {
                                        souvenirThumbnail(for: souvenir)
                                        VStack(alignment: .leading, spacing: 2) {
                                            Text(souvenir.displayTitle)
                                                .font(.subheadline.weight(.medium))
                                                .foregroundStyle(.primary)
                                            if let subtitle = souvenirSubtitle(for: souvenir) {
                                                Text(subtitle)
                                                    .font(.caption)
                                                    .foregroundStyle(.secondary)
                                            }
                                        }
                                        Spacer()
                                    }
                                    .padding(.horizontal, Tokens.Spacing.medium)
                                    .padding(.vertical, Tokens.Spacing.small)
                                }
                                .buttonStyle(.plain)
                                .contentShape(Rectangle())
                                .frame(maxWidth: .infinity, alignment: .leading)
                                if souvenir.id != sortedSouvenirs.last?.id {
                                    Divider().padding(.leading, 56)
                                }
                            }
                        }
                    }
                    .listRowBackground(Color.clear)
                    .listRowInsets(EdgeInsets(top: 2, leading: Tokens.Spacing.medium, bottom: 2, trailing: Tokens.Spacing.medium))
                    .listRowSeparator(.hidden)
                } else {
                    SearchResults(
                        resultsCount: displayed.count,
                        hasQuery: !trimmedQuery.isEmpty,
                        isSearching: isSearching,
                        showPrompt: false,
                        results: {
                            Section {
                                RoundedResultsCard {
                                    ForEach(displayed) { result in
                                        Button {
                                            selectResult(result)
                                        } label: {
                                            HStack(spacing: Tokens.Spacing.medium) {
                                                Image(systemName: "mappin.and.ellipse")
                                                    .foregroundStyle(Color.accentColor)
                                                VStack(alignment: .leading, spacing: 2) {
                                                    Text(result.title)
                                                        .font(.subheadline.weight(.medium))
                                                        .foregroundStyle(.primary)
                                                    if let subtitle = result.subtitle {
                                                        Text(subtitle)
                                                            .font(.caption)
                                                            .foregroundStyle(.secondary)
                                                    }
                                                }
                                                Spacer()
                                            }
                                            .padding(.horizontal, Tokens.Spacing.medium)
                                            .padding(.vertical, Tokens.Spacing.small)
                                        }
                                        .buttonStyle(.plain)
                                        .frame(maxWidth: .infinity, alignment: .leading)
                                        .contentShape(Rectangle())
                                        if result.id != displayed.last?.id {
                                            Divider().padding(.leading, 40)
                                        }
                                    }
                                }
                            }
                            .listRowBackground(Color.clear)
                            .listRowInsets(EdgeInsets(top: 2, leading: Tokens.Spacing.medium, bottom: 2, trailing: Tokens.Spacing.medium))
                            .listRowSeparator(.hidden)
                        },
                        empty: {
                            Section {
                                Text("No matches")
                                    .font(.caption)
                                    .foregroundStyle(.secondary)
                            }
                            .listRowBackground(Color.clear)
                        },
                        loading: {
                            Section {
                                HStack {
                                    Spacer()
                                    ProgressView()
                                    Spacer()
                                }
                            }
                            .listRowBackground(Color.clear)
                        },
                        prompt: {
                            EmptyView()
                        }
                    )
                }
            }
        )
    }

    private var inlineSearchField: some View {
        HStack(spacing: Tokens.Spacing.medium) {
            GlassSearchField(
                text: $query,
                placeholder: "Search for somewhere",
                font: .title2.weight(.regular),
                showClear: true,
                onSubmit: {
                    if isDetentSettled { triggerSearch(for: query) }
                }
            )
            .focused($isSearchFocused)
            .onChange(of: query) { _, newValue in
                handleQueryChange(newValue)
            }

            Button {
                islandState = .compact
            } label: {
                Image(systemName: "chevron.down")
                    .font(.headline.weight(.semibold))
                    .foregroundStyle(.secondary)
            }
            .buttonStyle(.plain)

            if showsConfirmButton && selectedResult != nil {
                confirmLocationButton
            }
        }
    }

    private var confirmLocationButton: some View {
        Button {
            guard !isConfirming else { return }
            isConfirming = true
            Task {
                let didSave = await onConfirmLocation?() ?? false
                await MainActor.run {
                    if didSave {
                        UIImpactFeedbackGenerator(style: .medium).impactOccurred()
                        didConfirmSuccess = true
                        DispatchQueue.main.asyncAfter(deadline: .now() + 1.0) {
                            didConfirmSuccess = false
                        }
                    }
                    isConfirming = false
                }
            }
        } label: {
            ZStack {
                Circle()
                    .fill(Color.successSvnr.opacity(DesignTokens.Opacity.strong))
                Circle()
                    .strokeBorder(.ultraThinMaterial, lineWidth: 1)
                Image(systemName: didConfirmSuccess ? "checkmark" : "checkmark.circle.fill")
                    .font(.caption.weight(.bold))
                    .foregroundStyle(.primary)
                    .symbolEffect(.bounce, options: .nonRepeating, value: didConfirmSuccess)
            }
            .frame(width: 32, height: 32)
        }
        .buttonStyle(.plain)
    }

    private var locationHeaderLabel: some View {
        Text(selectedResult?.title ?? "Where to be?")
            .font(.title2.weight(.semibold))
            .foregroundStyle(selectedResult == nil ? .secondary : .primary)
            .lineLimit(1)
    }

    private var searchAccessoryView: some View {
        Group {
            if islandState == .fullSheet {
                Image(systemName: "xmark")
                    .font(.caption.weight(.bold))
                    .foregroundStyle(.secondary)
                    .frame(width: 28, height: 28)
                    .background(.ultraThinMaterial, in: Circle())
                    .overlay(Circle().strokeBorder(Color.white.opacity(0.2), lineWidth: 1))
            } else {
                contextPhotoView
            }
        }
    }

    private var contextPhotoView: some View {
        ZStack {
            if let photo = contextPhotos.first {
                PhotoView(photo: photo)
                    .clipShape(Circle())
            } else {
                Image(systemName: "person.crop.circle.fill")
                    .font(.caption)
                    .foregroundStyle(.secondary)
            }
        }
        .frame(width: 28, height: 28)
        .background(.ultraThinMaterial, in: Circle())
        .overlay(Circle().strokeBorder(Color.white.opacity(0.2), lineWidth: 1))
    }

    private var sortedSouvenirs: [SouvenirEntity] {
        souvenirs.sorted { $0.updatedAt > $1.updatedAt }
    }

    private func souvenirSubtitle(for souvenir: SouvenirEntity) -> String? {
        if let meetPlace = souvenir.meetPlace, !meetPlace.isEmpty {
            return meetPlace
        }
        if let latest = souvenir.latestPhotoTimestamp {
            return DateFormatters.compactRelativeString(from: latest)
        }
        return nil
    }

    private func souvenirThumbnail(for souvenir: SouvenirEntity) -> some View {
        ZStack {
            if let photo = souvenir.favoritePhoto ?? souvenir.latestPhoto {
                PhotoView(photo: photo)
            } else {
                Rectangle()
                    .fill(.ultraThinMaterial)
                    .overlay(
                        Image(systemName: "photo")
                            .font(.caption)
                            .foregroundStyle(.secondary)
                    )
            }
        }
        .frame(width: 32, height: 32)
        .clipShape(Circle())
    }

    private func selectSouvenir(_ souvenir: SouvenirEntity) {
        isSearchFocused = false
        onSelectSouvenir?(souvenir)
        NotificationCenter.default.post(
            name: .svnrLocationSearchSouvenirSelected,
            object: nil,
            userInfo: ["souvenirID": souvenir.id]
        )
    }

    // MARK: - Actions

    private func handleQueryChange(_ newValue: String) {
        guard isDetentSettled else { return }
        if suppressNextSearch {
            suppressNextSearch = false
            return
        }
        triggerSearch(for: newValue)
    }

    private func triggerSearch(for query: String) {
        searchTask?.cancel()
        let trimmed = query.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !trimmed.isEmpty else {
            results = []
            isSearching = false
            selectedResult = nil
            return
        }
        if trimmed.count < 2 {
            results = []
            isSearching = false
            selectedResult = nil
            return
        }

        searchTask = Task {
            isSearching = true
            try? await Task.sleep(for: .milliseconds(250))
            guard !Task.isCancelled else { return }
            await searchLocations(query: trimmed)
        }
    }

    private func searchLocations(query: String) async {
        do {
            let results = try await searchService.searchLocations(query: query, region: searchRegion)
            await MainActor.run {
                self.results = results
                self.isSearching = false
            }
        } catch {
            await MainActor.run {
                self.results = []
                self.isSearching = false
            }
        }
    }

    private func selectResult(_ result: LocationSearchResult) {
        selectedResult = result
        didConfirmSuccess = false
        query = result.title
        suppressNextSearch = true
        isSearchFocused = false
        withAnimation(ContactIslandAnimation.spring) {
            islandState = .fullSheet
        }
        onSelectLocation?(result)
    }

    private func markUnsettledThenSettle() {
        isDetentSettled = false
        DispatchQueue.main.asyncAfter(deadline: .now() + 0.18) {
            isDetentSettled = true
        }
    }

}

private struct LocationSearchIslandPreviewHost: View {
    let initialState: ContactIslandState
    @State private var islandState: ContactIslandState

    init(initialState: ContactIslandState) {
        self.initialState = initialState
        _islandState = State(initialValue: initialState)
    }

    var body: some View {
        let context = PersistenceController.preview.container.viewContext
        let request: NSFetchRequest<SouvenirEntity> = SouvenirEntity.fetchRequest()
        request.fetchLimit = 1
        let souvenir = (try? context.fetch(request).first)
        let photoID = souvenir?.favoritePhoto?.id ?? UUID()
        let souvenirID = souvenir?.id ?? UUID()
        let searchContext = LocationSearchContext(
            photoID: photoID,
            souvenirID: souvenirID,
            latitude: 37.3349,
            longitude: -122.0090,
            assetLocalId: souvenir?.favoritePhoto?.assetLocalId
        )

        return ZStack {
            Color.black.opacity(0.2).ignoresSafeArea()
            Text("Map Preview")
                .foregroundStyle(.white.opacity(0.6))
        }
        .sheet(isPresented: .constant(true)) {
            LocationSearchIsland(
                context: searchContext,
                searchRegion: MKCoordinateRegion(
                    center: CLLocationCoordinate2D(latitude: 37.3349, longitude: -122.0090),
                    span: MKCoordinateSpan(latitudeDelta: 0.05, longitudeDelta: 0.05)
                ),
                islandState: $islandState
            )
            .task {
                await Task.yield()
                islandState = initialState
            }
        }
        .environment(\.managedObjectContext, context)
    }
}

#Preview("Location Search Island - Compact") {
    LocationSearchIslandPreviewHost(initialState: .compact)
}

#Preview("Location Search Island - Half Open") {
    LocationSearchIslandPreviewHost(initialState: .fullSheet)
}

#Preview("Location Search Island - Full Sheet") {
    LocationSearchIslandPreviewHost(initialState: .fullSheet)
}

import SwiftUI

/// Generic search results container with optional loading, empty, and prompt states.
struct SearchResults<Results: View, Empty: View, Loading: View, Prompt: View>: View {
    let resultsCount: Int
    let hasQuery: Bool
    let isSearching: Bool
    let showPrompt: Bool
    let results: Results
    let empty: Empty
    let loading: Loading
    let prompt: Prompt

    init(
        resultsCount: Int,
        hasQuery: Bool,
        isSearching: Bool,
        showPrompt: Bool = false,
        @ViewBuilder results: () -> Results,
        @ViewBuilder empty: () -> Empty,
        @ViewBuilder loading: () -> Loading,
        @ViewBuilder prompt: () -> Prompt
    ) {
        self.resultsCount = resultsCount
        self.hasQuery = hasQuery
        self.isSearching = isSearching
        self.showPrompt = showPrompt
        self.results = results()
        self.empty = empty()
        self.loading = loading()
        self.prompt = prompt()
    }

    var body: some View {
        if resultsCount > 0 {
            results
        } else if isSearching {
            loading
        } else if showPrompt {
            prompt
        } else if hasQuery {
            empty
        }
    }
}

