Perfect. Now I'll refactor this. The key changes:
1. Remove `showPrompt` from SearchResults - it won't be used
2. Move the button logic outside SearchResults into a VStack
3. Always show the button when `!isContactsAuthorized`, regardless of whether there are results
4. Update the SearchResults call to no longer use `showPrompt`

Here's the refactored version:

```swift
private var contactSearchResults: some View {
    let trimmed = contactQuery.trimmingCharacters(in: .whitespacesAndNewlines)
    var resultsToShow = Array(contactResults.prefix(7))
    if resultsToShow.isEmpty, !trimmed.isEmpty {
        resultsToShow = [.new(trimmed)]
    }

    return VStack(spacing: Tokens.Spacing.medium) {
        // Always show permission prompt when unauthorized
        if !isContactsAuthorized {
            Button {
                if contactsPermissionStatus == .notDetermined {
                    shouldReopenContactSearch = true
                    showContactSearch = false
                    DispatchQueue.main.asyncAfter(deadline: .now() + 0.35) {
                        showContactsPrimer = true
                    }
                } else {
                    openContactsSettings()
                }
            } label: {
                HStack {
                    Spacer()
                    Text(contactsPermissionStatus == .notDetermined ? "Search your contacts 🧐" : "Enable Contacts ⚙️")
                        .font(.title2.weight(.medium))
                        .foregroundStyle(.primary)
                    Spacer()
                    if contactsPermissionStatus != .notDetermined {
                        Image(systemName: "arrow.up.right.square")
                            .font(.caption.weight(.semibold))
                            .foregroundStyle(.secondary)
                    }
                }
                .padding(.horizontal, Tokens.Spacing.large)
                .padding(.vertical, Tokens.Spacing.medium)
            }
            .buttonStyle(.plain)
            .contentShape(Rectangle())
            .background(.thinMaterial, in: Capsule())
            .overlay(
                Capsule()
                    .strokeBorder(.primary.opacity(0.2), lineWidth: 1)
            )
            .padding(.horizontal, Tokens.Spacing.medium)
        }

        // Search results below
        SearchResults(
            resultsCount: resultsToShow.count,
            results: resultsToShow,
            onSelect: handleContactSelection
        )
    }
}
```

The button now displays conditionally based on authorization status, with different text and styling for the two permission states. The SearchResults component is simplified and always rendered below the permission prompt when needed.

