        selectedContact?.imageThumbData ?? souvenir?.primaryContact?.imageThumbData
    }

    private func reviewContactAvatar(size: CGFloat) -> some View {
        Group {
            if let data = reviewContactImageData,
               let image = UIImage(data: data) {
                Image(uiImage: image)
                    .resizable()
                    .aspectRatio(contentMode: .fill)
                    .frame(width: size, height: size)
                    .clipShape(Circle())
            }
        }
    }

    private var shouldShowEmailField: Bool {
        guard let contact = selectedContact else { return false }
        return !(contact.email?.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty ?? true)
    }

    private var shouldShowAddressField: Bool {
        guard let contact = selectedContact else { return false }
        return !(contact.address?.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty ?? true)
    }

    private var birthdayBinding: Binding<Date?> {
        Binding(
            get: { birthday },
            set: { birthday = $0 }
        )
    }

    private var giveSouvenirButton: some View {
        HStack {
            Spacer()
            Button {
                guard hasAttachedPhoto else { return }
                if isSelfie {
                    completeSelfieSouvenir()
                } else {
                    saveContactEdits()
                    contactDetailsMode = .view
                    pendingShareSheet = true
                    showContactDetails = false
                }
            } label : {
                HStack(spacing: DesignTokens.Spacing.small) {
                    Spacer()
                    Image(systemName: "square.and.arrow.down.fill")
                        .font(.title3.weight(.medium))
                        .symbolRenderingMode(.hierarchical)
                        .foregroundStyle(.primary)
                    Text(isSelfie ? "Save Souvenir" : "Share Souvenir")
                        .font(.title3.weight(.medium))
                        .foregroundStyle(.primary)
                    Spacer()
                }
                .padding(.horizontal, DesignTokens.Spacing.large)
                .padding(.vertical, DesignTokens.Spacing.medium)
            }
            .buttonStyle(.plain)
            .contentShape(Rectangle())
            .background(.thinMaterial, in: Capsule())
            .overlay(
                Capsule()
                    .strokeBorder(.primary.opacity(0.2), lineWidth: 1)
            )
            Spacer()
        }
        .disabled(!hasAttachedPhoto)
        .listRowBackground(Color.infoSvnr.opacity(DesignTokens.Opacity.light))
    }

    private var viewHeader: some View {
        HStack {
            Text(selectedContact?.displayName ?? "Untitled")
                .font(.title2.weight(.semibold))
            Spacer()
            NakedIconButton(systemName: "pencil") {
                contactDetailsMode = .review
            }
        }
    }

    private var viewDetails: some View {
        VStack(alignment: .leading, spacing: DesignTokens.Spacing.small) {
            if !phoneText.isEmpty {
                ContactInfoRow(systemImage: "phone", text: phoneText)
            }
            if !emailText.isEmpty {
                ContactInfoRow(systemImage: "envelope", text: emailText)
            }
        }
    }

    private var viewFooter: some View {
        PrimaryCtaButton(title: "Share") {
            guard hasAttachedPhoto else { return }
            pendingShareSheet = true
            showContactDetails = false
        }
        .disabled(!hasAttachedPhoto)
    }

    private func saveContactEdits() {
        guard let souvenir else { return }
        guard let contact = selectedContact ?? souvenir.primaryContact else { return }
        let souvenirID = souvenir.objectID
        let contactID = contact.objectID
        viewContext.perform {
            guard let souvenirInContext = viewContext.object(with: souvenirID) as? SouvenirEntity,
                  let contactInContext = viewContext.object(with: contactID) as? ContactEntity else { return }

            contactInContext.compositeName = nameText
            contactInContext.givenName = nameText
            contactInContext.phoneE164 = phoneText
            contactInContext.email = emailText
            contactInContext.address = addressText
            contactInContext.birthday = birthday

            souvenirInContext.primaryContact = contactInContext
            souvenirInContext.isSelfie = isSelfie
            if isSelfie {
                SelfContactService.shared.setSelfContactOnContextQueue(contactID: contactInContext.id, in: viewContext)
            }

            // Ensure permanent IDs for souvenir, contact, and any photos before presenting share
            var objects: [NSManagedObject] = [souvenirInContext, contactInContext]
            for p in souvenirInContext.photosArray { objects.append(p) }
            let tempObjects = objects.filter { $0.objectID.isTemporaryID }
            if !tempObjects.isEmpty {
                try? viewContext.obtainPermanentIDs(for: tempObjects)
            }
            try? viewContext.save()
        }
    }

    private func ensurePermanentIDsForShare() {
        guard let souvenir else { return }
        let souvenirID = souvenir.objectID
        viewContext.performAndWait {
            guard let souvenirInContext = viewContext.object(with: souvenirID) as? SouvenirEntity else { return }
            var objects: [NSManagedObject] = [souvenirInContext]
            if let contact = souvenirInContext.primaryContact { objects.append(contact) }
            for p in souvenirInContext.photosArray { objects.append(p) }
            let tempObjects = objects.filter { $0.objectID.isTemporaryID }
            if !tempObjects.isEmpty {
                try? viewContext.obtainPermanentIDs(for: tempObjects)
            }
            try? viewContext.save()
        }
    }

    private func navigateToSouvenirIfReady() {
        guard let souvenir else { return }
        router.navigate(to: .souvenir(id: souvenir.id))
    }

    private func completeSelfieSouvenir() {
        saveContactEdits()
        if let souvenir {
            newSouvenirTracker.trackNewSouvenir(souvenir.id)
        }
        showContactDetails = false
        newSouvenirTracker.requestReturnToOrigin()
    }
}

