    16→/// Fast, native camera view using AVFoundation (like iOS Messages/Camera app)
    17→struct CustomCameraView: View {
    18→    @Environment(\.dismiss) private var dismiss
    19→    @StateObject private var camera = CameraController()
    20→    @StateObject private var locationManager = CameraLocationManager()
    21→    @Binding var selectedPhoto: PhotosPickerItem?
    22→    private let promptForLocationOnOpen: Bool
    23→
    24→    /// Most recent photo thumbnail from library
    25→    @State private var recentPhotoThumbnail: UIImage?
    26→    /// Track the previous selected photo to detect changes
    27→    @State private var previousSelectedPhoto: PhotosPickerItem?
    28→    @State private var isProcessingLibrarySelection = false
    29→    @State private var pendingLibraryDismiss = false
    30→    @State private var isLibraryVisible = false
    31→    @State private var showPhotosPrimer = false
    32→    @State private var showPhotosPicker = false
    33→    let onCapture: (UIImage, CLLocation?) -> Void
    34→    let onCancel: () -> Void
    35→    
    36→    init(
    37→        selectedPhoto: Binding<PhotosPickerItem?>,
    38→        promptForLocationOnOpen: Bool = true,
    39→        onCapture: @escaping (UIImage, CLLocation?) -> Void,
    40→        onCancel: @escaping () -> Void = {}
    41→    ) {
    42→        self._selectedPhoto = selectedPhoto
    43→        self.promptForLocationOnOpen = promptForLocationOnOpen
    44→        self.onCapture = onCapture
    45→        self.onCancel = onCancel
    46→    }
    47→    
    48→    var body: some View {
    49→        ZStack {
