    97→                    camera.flipCamera()
    98→                },
    99→                libraryButton: {
   100→                    libraryButton
   101→                }
   102→            )
   103→        }
   104→        .statusBarHidden()
   105→        .onAppear {
   106→            camera.startSession()
   107→            // Request location permission to capture coordinates with photo
   108→            locationManager.requestPermissionIfNeeded(promptIfNeeded: promptForLocationOnOpen)
   109→        }
   110→        .onDisappear {
   111→            camera.stopSession()
   112→        }
   113→        .task {
   114→            await loadRecentPhotoThumbnail()
   115→        }
   116→        .onChange(of: selectedPhoto) { oldValue, newValue in
   117→            guard !isProcessingLibrarySelection else {
   118→                return
   119→            }
