   184→                        .clipShape(RoundedRectangle(cornerRadius: DesignTokens.CornerRadius.small, style: .continuous))
   185→                        .overlay(
   186→                            RoundedRectangle(cornerRadius: DesignTokens.CornerRadius.small, style: .continuous)
   187→                                .stroke(.white.opacity(DesignTokens.Opacity.semi), lineWidth: 1)
   188→                        )
   189→                        .shadow(radius: 2)
   190→                } else {
   191→                    Image(systemName: "photo.on.rectangle")
   192→                        .font(.system(size: 32))
   193→                        .foregroundStyle(.primary)
   194→                        .frame(width: DesignTokens.Size.navButton, height: DesignTokens.Size.navButton)
   195→                }
   196→            }
   197→        }
   198→        .buttonStyle(.plain)
   199→        .disabled(isProcessingLibrarySelection)
   200→        .opacity(isProcessingLibrarySelection ? 0.4 : 1)
   201→        .accessibilityLabel("Choose photo from library")
   202→        .photosPicker(
   203→            isPresented: $showPhotosPicker,
   204→            selection: $selectedPhoto,
   205→            matching: .images,
   206→            photoLibrary: .shared()
   207→        )
   208→    }
