   210→    private func loadRecentPhotoThumbnail() async {
   211→        let status = PHPhotoLibrary.authorizationStatus(for: .readWrite)
   212→        guard status == .authorized || status == .limited else { return }
   213→
   214→        let options = PHFetchOptions()
   215→        options.sortDescriptors = [NSSortDescriptor(key: "creationDate", ascending: false)]
   216→        options.fetchLimit = 1
   217→
   218→        let result = PHAsset.fetchAssets(with: .image, options: options)
   219→        guard let asset = result.firstObject else { return }
   220→
   221→        let imageOptions = PHImageRequestOptions()
   222→        imageOptions.isSynchronous = false
   223→        imageOptions.deliveryMode = .opportunistic
   224→        imageOptions.resizeMode = .fast
   225→
   226→        let targetSize = CGSize(width: 80, height: 80)
   227→
   228→        PHImageManager.default().requestImage(
   229→            for: asset,
   230→            targetSize: targetSize,
   231→            contentMode: .aspectFill,
   232→            options: imageOptions
   233→        ) { image, _ in
   234→            if let image = image {
   235→                Task { @MainActor in
   236→                    recentPhotoThumbnail = image
   237→                }
   238→            }
   239→        }
   240→    }
   241→}
