   287→// MARK: - Camera Controller
   288→
   289→@MainActor
   290→class CameraController: NSObject, ObservableObject {
   291→    let session = AVCaptureSession()
   292→    private let photoOutput = AVCapturePhotoOutput()
   293→    private var currentCamera: AVCaptureDevice?
   294→    private var captureCompletion: ((UIImage) -> Void)?
   295→    private let sessionID = UUID().uuidString
   296→    private var hasStopped = false  // Prevent redundant stop calls
   297→
   298→    @Published var flashMode: AVCaptureDevice.FlashMode = .off
   299→    @Published var cameraPosition: AVCaptureDevice.Position = .front
   300→
   301→    override init() {
   302→        super.init()
   303→        setupSession()
   304→        print("📹 CameraController[\(sessionID)] initialized")
   305→    }
   306→    
   307→    deinit {
   308→        print("📹 CameraController[\(sessionID)] deinitialized")
   309→        // Note: Cannot call main actor-isolated methods from deinit
   310→        // Session cleanup is handled by stopSession() which is called before dismissal
   311→    }
   312→    
   313→    private func setupSession() {
   314→        session.beginConfiguration()
   315→        
   316→        // Set preset
   317→        if session.canSetSessionPreset(.photo) {
   318→            session.sessionPreset = .photo
   319→        }
   320→        
   321→        // Add camera input (front camera by default)
   322→        if let camera = getCamera(for: .front) {
   323→            do {
   324→                let input = try AVCaptureDeviceInput(device: camera)
   325→                if session.canAddInput(input) {
   326→                    session.addInput(input)
   327→                    currentCamera = camera
   328→                }
   329→            } catch {
   330→                print("❌ Failed to add camera input: \(error)")
   331→            }
   332→        }
   333→        
   334→        // Add photo output
   335→        if session.canAddOutput(photoOutput) {
   336→            session.addOutput(photoOutput)
   337→            
   338→            // AVFoundation doesn't auto-save to the Photo Library.
   339→            // The app handles library writes later (after the Photos primer).
   340→            
   341→            // Configure output
   342→            if let connection = photoOutput.connection(with: .video) {
   343→                if connection.isVideoMirroringSupported {
   344→                    connection.isVideoMirrored = (cameraPosition == .front)
   345→                }
   346→            }
   347→        }
   348→        
   349→        session.commitConfiguration()
   350→    }
   351→    
   352→    nonisolated func startSession() {
   353→        Task.detached { [weak self] in
   354→            guard let self = self else { return }
   355→            await self.session.startRunning()
   356→            await MainActor.run {
   357→                print("📹 CameraController[\(self.sessionID)] session STARTED (isRunning: \(self.session.isRunning))")
   358→                CameraStateMonitor.shared.registerSession(self.sessionID)
   359→            }
   360→        }
   361→    }
   362→    
   363→    func stopSession() {
   364→        // Guard against redundant stop calls (from capture, dismiss, disappear, deinit)
   365→        guard !hasStopped else {
   366→            return
   367→        }
   368→        hasStopped = true
   369→
   370→        // Stop synchronously to ensure camera resources are released immediately
   371→        // This prevents resource contention when text input needs to initialize
   372→        print("📹 CameraController[\(sessionID)] stopSession() called (isRunning: \(session.isRunning))")
   373→
   374→        if session.isRunning {
   375→            session.stopRunning()
   376→        }
   377→
   378→        CameraStateMonitor.shared.unregisterSession(sessionID)
   379→        print("🎥 Camera session stopped for \(sessionID)")
   380→    }
   381→    
   382→    func flipCamera() {
   383→        let newPosition: AVCaptureDevice.Position = (cameraPosition == .front) ? .back : .front
   384→        
   385→        guard let newCamera = getCamera(for: newPosition) else {
   386→            print("⚠️ Camera not available for position: \(newPosition.rawValue)")
   387→            return
   388→        }
   389→        
   390→        session.beginConfiguration()
   391→        
   392→        // Remove current input
   393→        if let currentInput = session.inputs.first as? AVCaptureDeviceInput {
   394→            session.removeInput(currentInput)
   395→        }
   396→        
   397→        // Add new input
   398→        do {
   399→            let newInput = try AVCaptureDeviceInput(device: newCamera)
   400→            if session.canAddInput(newInput) {
   401→                session.addInput(newInput)
   402→                currentCamera = newCamera
   403→                cameraPosition = newPosition
   404→                
   405→                // Update mirroring for front camera
   406→                if let connection = photoOutput.connection(with: .video),
   407→                   connection.isVideoMirroringSupported {
   408→                    connection.isVideoMirrored = (newPosition == .front)
   409→                }
   410→            }
   411→        } catch {
   412→            print("❌ Failed to flip camera: \(error)")
   413→        }
   414→        
   415→        session.commitConfiguration()
   416→    }
   417→    
   418→    func toggleFlash() {
   419→        switch flashMode {
   420→        case .off:
   421→            flashMode = .on
   422→        case .on:
   423→            flashMode = .auto
   424→        case .auto:
   425→            flashMode = .off
   426→        @unknown default:
   427→            flashMode = .off
   428→        }
   429→    }
   430→    
   431→    func capturePhoto(completion: @escaping (UIImage) -> Void) {
   432→        self.captureCompletion = completion
   433→        
   434→        let settings = AVCapturePhotoSettings()
   435→        
   436→        // Set flash mode
   437→        if photoOutput.supportedFlashModes.contains(flashMode) {
   438→            settings.flashMode = flashMode
   439→        }
   440→        
   441→        photoOutput.capturePhoto(with: settings, delegate: self)
   442→    }
   443→    
   444→    private func getCamera(for position: AVCaptureDevice.Position) -> AVCaptureDevice? {
   445→        // Try to get the best camera for the position
   446→        if let device = AVCaptureDevice.default(.builtInWideAngleCamera, for: .video, position: position) {
   447→            return device
   448→        }
   449→        
   450→        // Fallback to any camera in that position using AVCaptureDeviceDiscoverySession
   451→        let discoverySession = AVCaptureDevice.DiscoverySession(
   452→            deviceTypes: [.builtInWideAngleCamera, .builtInTelephotoCamera, .builtInUltraWideCamera],
   453→            mediaType: .video,
   454→            position: position
   455→        )
   456→        return discoverySession.devices.first
   457→    }
   458→}
