   460→// MARK: - Photo Capture Delegate
   461→
   462→extension CameraController: AVCapturePhotoCaptureDelegate {
   463→    nonisolated func photoOutput(
   464→        _ output: AVCapturePhotoOutput,
   465→        didFinishProcessingPhoto photo: AVCapturePhoto,
   466→        error: Error?
   467→    ) {
   468→        if let error = error {
   469→            print("❌ Photo capture error: \(error)")
   470→            return
   471→        }
   472→        
   473→        guard let imageData = photo.fileDataRepresentation(),
   474→              let image = UIImage(data: imageData) else {
   475→            print("❌ Failed to create image from photo data")
   476→            return
   477→        }
   478→        
   479→        // Call completion on main actor
   480→        Task { @MainActor in
   481→            self.captureCompletion?(image)
   482→            self.captureCompletion = nil
   483→        }
   484→    }
   485→}
