   487→// MARK: - Camera Location Manager
   488→
   489→/// Lightweight location manager to request permission when camera opens
   490→/// This ensures location is available when the photo is captured
   491→@MainActor
   492→class CameraLocationManager: NSObject, ObservableObject, CLLocationManagerDelegate {
   493→    private let manager = CLLocationManager()
   494→    
   495→    /// Current location (if available)
   496→    @Published var location: CLLocation?
   497→    private var pendingContinuations: [CheckedContinuation<CLLocation?, Never>] = []
   498→    private var timeoutTask: Task<Void, Never>?
   499→    private var isRequestingLocation = false
   500→
   501→    override init() {
   502→        super.init()
   503→        manager.delegate = self
   504→        manager.desiredAccuracy = kCLLocationAccuracyBest
   505→    }
   506→
   507→    func requestPermissionIfNeeded(promptIfNeeded: Bool = true) {
   508→        let status = manager.authorizationStatus
   509→        if status == .notDetermined {
   510→            if promptIfNeeded {
   511→                manager.requestWhenInUseAuthorization()
   512→            }
   513→        } else if status == .authorizedWhenInUse || status == .authorizedAlways {
   514→            manager.startUpdatingLocation()
   515→        }
   516→    }
   517→
   518→    /// Await a location update with a timeout (returns nil if not authorized or timed out).
   519→    func awaitCurrentLocation(timeout: TimeInterval) async -> CLLocation? {
   520→        let start = Date()
   521→        var status = manager.authorizationStatus
   522→
   523→        if status == .notDetermined {
   524→            manager.requestWhenInUseAuthorization()
   525→            while status == .notDetermined,
   526→                  Date().timeIntervalSince(start) < timeout {
   527→                try? await Task.sleep(for: .milliseconds(150))
   528→                status = manager.authorizationStatus
