//
//  CustomCameraView.swift
//  souvenir
//
//  Created by Kerrbear on 17.01.2026.
//

import SwiftUI
import AVFoundation
import UIKit
import Combine
import PhotosUI
import Photos
import CoreLocation

/// Fast, native camera view using AVFoundation (like iOS Messages/Camera app)
struct CustomCameraView: View {
    @Environment(\.dismiss) private var dismiss
    @StateObject private var camera = CameraController()
    @StateObject private var locationManager = CameraLocationManager()
    @Binding var selectedPhoto: PhotosPickerItem?
    private let promptForLocationOnOpen: Bool

    /// Most recent photo thumbnail from library
    @State private var recentPhotoThumbnail: UIImage?
    /// Track the previous selected photo to detect changes
    @State private var previousSelectedPhoto: PhotosPickerItem?
    @State private var isProcessingLibrarySelection = false
    @State private var pendingLibraryDismiss = false
    @State private var isLibraryVisible = false
    @State private var showPhotosPrimer = false
    @State private var showPhotosPicker = false
    let onCapture: (UIImage, CLLocation?) -> Void
    let onCancel: () -> Void

    init(
        selectedPhoto: Binding<PhotosPickerItem?>,
        promptForLocationOnOpen: Bool = true,
        onCapture: @escaping (UIImage, CLLocation?) -> Void,
        onCancel: @escaping () -> Void = {}
    ) {
        self._selectedPhoto = selectedPhoto
        self.promptForLocationOnOpen = promptForLocationOnOpen
        self.onCapture = onCapture
        self.onCancel = onCancel
    }

    var body: some View {
        ZStack {
            // Camera preview
            CameraPreviewView(session: camera.session)
                .ignoresSafeArea()
                .contentShape(Rectangle())
                .opacity(isLibraryVisible ? 0 : 1)
                .onTapGesture(count: 2) {
                    guard !isLibraryVisible else { return }
                    camera.flipCamera()
                    UIImpactFeedbackGenerator(style: .light).impactOccurred()
                }

            if isProcessingLibrarySelection {
                Rectangle()
                    .fill(.black.opacity(0.45))
                    .ignoresSafeArea()
                ProgressView()
                    .tint(.white)
                    .scaleEffect(1.2)
            }

            if isLibraryVisible {
                Rectangle()
                    .fill(.black)
                    .ignoresSafeArea()
            }

            CameraControls(
                flashIcon: camera.flashMode == .on ? "bolt.fill" : camera.flashMode == .auto ? "bolt.badge.automatic" : "bolt.slash.fill",
                onCancel: {
                    camera.stopSession()
                    onCancel()
                    dismiss()
                },
                onToggleFlash: {
                    camera.toggleFlash()
                },
                onCapture: {
                    camera.capturePhoto { image in
                        camera.stopSession()
                        Task {
                            let location = await locationManager.awaitCurrentLocation(timeout: 3.0)
                            onCapture(image, location)
                            dismiss()
                        }
                    }
                },
                onFlip: {
                    camera.flipCamera()
                },
                libraryButton: {
                    libraryButton
                }
            )
        }
        .statusBarHidden()
        .onAppear {
            camera.startSession()
            // Request location permission to capture coordinates with photo
            locationManager.requestPermissionIfNeeded(promptIfNeeded: promptForLocationOnOpen)
        }
        .onDisappear {
            camera.stopSession()
        }
        .task {
            await loadRecentPhotoThumbnail()
        }
        .onChange(of: selectedPhoto) { oldValue, newValue in
            guard !isProcessingLibrarySelection else {
                return
            }
            // When a photo is selected from the library, dismiss the camera view
            if newValue != nil && newValue != previousSelectedPhoto {
                print("📸 Photo selected from library, dismissing camera view")
                isProcessingLibrarySelection = true
                pendingLibraryDismiss = true
                camera.stopSession()
            }
            // Update the previous value for next comparison
            previousSelectedPhoto = newValue
        }
        .onChange(of: showPhotosPicker) { _, isPresented in
            if isPresented {
                isLibraryVisible = true
                camera.stopSession()
                return
            }
            if pendingLibraryDismiss, selectedPhoto != nil {
                pendingLibraryDismiss = false
                dismiss()
                return
            }
            if selectedPhoto == nil {
                isLibraryVisible = false
                camera.startSession()
            }
        }
        .sheet(isPresented: $showPhotosPrimer) {
            SouvenirPhotosPrimerView(
                onContinue: {
                    Task {
                        let status = await PHPhotoLibrary.requestAuthorization(for: .readWrite)
                        await MainActor.run {
                            if status == .authorized || status == .limited {
                                showPhotosPicker = true
                            }
                        }
                    }
                },
                onCancel: {}
            )
        }
    }

    private var libraryButton: some View {
        Button {
            guard !isProcessingLibrarySelection else { return }
            let status = PHPhotoLibrary.authorizationStatus(for: .readWrite)
            switch status {
            case .authorized, .limited:
                showPhotosPicker = true
            case .notDetermined:
                showPhotosPrimer = true
            case .denied, .restricted:
                break
            @unknown default:
                break
            }
        } label: {
            Group {
                if let thumbnail = recentPhotoThumbnail {
                    Image(uiImage: thumbnail)
                        .resizable()
                        .aspectRatio(contentMode: .fill)
                        .frame(width: DesignTokens.Size.navButton, height: DesignTokens.Size.navButton)
                        .clipShape(RoundedRectangle(cornerRadius: DesignTokens.CornerRadius.small, style: .continuous))
                        .overlay(
                            RoundedRectangle(cornerRadius: DesignTokens.CornerRadius.small, style: .continuous)
                                .stroke(.white.opacity(DesignTokens.Opacity.semi), lineWidth: 1)
                        )
                        .shadow(radius: 2)
                } else {
                    Image(systemName: "photo.on.rectangle")
                        .font(.system(size: 32))
                        .foregroundStyle(.primary)
                        .frame(width: DesignTokens.Size.navButton, height: DesignTokens.Size.navButton)
                }
            }
        }
        .buttonStyle(.plain)
        .disabled(isProcessingLibrarySelection)
        .opacity(isProcessingLibrarySelection ? 0.4 : 1)
        .accessibilityLabel("Choose photo from library")
        .photosPicker(
            isPresented: $showPhotosPicker,
            selection: $selectedPhoto,
            matching: .images,
            photoLibrary: .shared()
        )
    }

    private func loadRecentPhotoThumbnail() async {
        let status = PHPhotoLibrary.authorizationStatus(for: .readWrite)
        guard status == .authorized || status == .limited else { return }

        let options = PHFetchOptions()
        options.sortDescriptors = [NSSortDescriptor(key: "creationDate", ascending: false)]
        options.fetchLimit = 1

        let result = PHAsset.fetchAssets(with: .image, options: options)
        guard let asset = result.firstObject else { return }

        let imageOptions = PHImageRequestOptions()
        imageOptions.isSynchronous = false
        imageOptions.deliveryMode = .opportunistic
        imageOptions.resizeMode = .fast

        let targetSize = CGSize(width: 80, height: 80)

        PHImageManager.default().requestImage(
            for: asset,
            targetSize: targetSize,
            contentMode: .aspectFill,
            options: imageOptions
        ) { image, _ in
            if let image = image {
                Task { @MainActor in
                    recentPhotoThumbnail = image
                }
            }
        }
    }
}


// MARK: - Camera Preview

/// UIKit view that displays the camera feed
struct CameraPreviewView: UIViewRepresentable {
    let session: AVCaptureSession

    func makeUIView(context: Context) -> CameraPreviewUIView {
        let view = CameraPreviewUIView()
        view.session = session
        return view
    }

    func updateUIView(_ uiView: CameraPreviewUIView, context: Context) {
        // No updates needed
    }
}

class CameraPreviewUIView: UIView {
    var session: AVCaptureSession? {
        didSet {
            guard let session = session else { return }
            previewLayer.session = session
        }
    }

    override class var layerClass: AnyClass {
        AVCaptureVideoPreviewLayer.self
    }

    var previewLayer: AVCaptureVideoPreviewLayer {
        layer as! AVCaptureVideoPreviewLayer
    }

    override init(frame: CGRect) {
        super.init(frame: frame)
        previewLayer.videoGravity = .resizeAspectFill
    }

    required init?(coder: NSCoder) {
        fatalError("init(coder:) has not been implemented")
    }
}

// MARK: - Camera Controller

@MainActor
class CameraController: NSObject, ObservableObject {
    let session = AVCaptureSession()
    private let photoOutput = AVCapturePhotoOutput()
    private var currentCamera: AVCaptureDevice?
    private var captureCompletion: ((UIImage) -> Void)?
    private let sessionID = UUID().uuidString
    private var hasStopped = false  // Prevent redundant stop calls

    @Published var flashMode: AVCaptureDevice.FlashMode = .off
    @Published var cameraPosition: AVCaptureDevice.Position = .front

    override init() {
        super.init()
        setupSession()
        print("📹 CameraController[\(sessionID)] initialized")
    }

    deinit {
        print("📹 CameraController[\(sessionID)] deinitialized")
        // Note: Cannot call main actor-isolated methods from deinit
        // Session cleanup is handled by stopSession() which is called before dismissal
    }

    private func setupSession() {
        session.beginConfiguration()

        // Set preset
        if session.canSetSessionPreset(.photo) {
            session.sessionPreset = .photo
        }

        // Add camera input (front camera by default)
        if let camera = getCamera(for: .front) {
            do {
                let input = try AVCaptureDeviceInput(device: camera)
                if session.canAddInput(input) {
                    session.addInput(input)
                    currentCamera = camera
                }
            } catch {
                print("❌ Failed to add camera input: \(error)")
            }
        }

        // Add photo output
        if session.canAddOutput(photoOutput) {
            session.addOutput(photoOutput)

            // AVFoundation doesn't auto-save to the Photo Library.
            // The app handles library writes later (after the Photos primer).

            // Configure output
            if let connection = photoOutput.connection(with: .video) {
                if connection.isVideoMirroringSupported {
                    connection.isVideoMirrored = (cameraPosition == .front)
                }
            }
        }

        session.commitConfiguration()
    }

    nonisolated func startSession() {
        Task.detached { [weak self] in
            guard let self = self else { return }
            await self.session.startRunning()
            await MainActor.run {
                print("📹 CameraController[\(self.sessionID)] session STARTED (isRunning: \(self.session.isRunning))")
                CameraStateMonitor.shared.registerSession(self.sessionID)
            }
        }
    }

    func stopSession() {
        // Guard against redundant stop calls (from capture, dismiss, disappear, deinit)
        guard !hasStopped else {
            return
        }
        hasStopped = true

        // Stop synchronously to ensure camera resources are released immediately
        // This prevents resource contention when text input needs to initialize
        print("📹 CameraController[\(sessionID)] stopSession() called (isRunning: \(session.isRunning))")

        if session.isRunning {
            session.stopRunning()
        }

        CameraStateMonitor.shared.unregisterSession(sessionID)
        print("🎥 Camera session stopped for \(sessionID)")
    }

    func flipCamera() {
        let newPosition: AVCaptureDevice.Position = (cameraPosition == .front) ? .back : .front

        guard let newCamera = getCamera(for: newPosition) else {
            print("⚠️ Camera not available for position: \(newPosition.rawValue)")
            return
        }

        session.beginConfiguration()

        // Remove current input
        if let currentInput = session.inputs.first as? AVCaptureDeviceInput {
            session.removeInput(currentInput)
        }

        // Add new input
        do {
            let newInput = try AVCaptureDeviceInput(device: newCamera)
            if session.canAddInput(newInput) {
                session.addInput(newInput)
                currentCamera = newCamera
                cameraPosition = newPosition

                // Update mirroring for front camera
                if let connection = photoOutput.connection(with: .video),
                   connection.isVideoMirroringSupported {
                    connection.isVideoMirrored = (newPosition == .front)
                }
            }
        } catch {
            print("❌ Failed to flip camera: \(error)")
        }

        session.commitConfiguration()
    }

    func toggleFlash() {
        switch flashMode {
        case .off:
            flashMode = .on
        case .on:
            flashMode = .auto
        case .auto:
            flashMode = .off
        @unknown default:
            flashMode = .off
        }
    }

    func capturePhoto(completion: @escaping (UIImage) -> Void) {
        self.captureCompletion = completion

        let settings = AVCapturePhotoSettings()

        // Set flash mode
        if photoOutput.supportedFlashModes.contains(flashMode) {
            settings.flashMode = flashMode
        }

        photoOutput.capturePhoto(with: settings, delegate: self)
    }

    private func getCamera(for position: AVCaptureDevice.Position) -> AVCaptureDevice? {
        // Try to get the best camera for the position
        if let device = AVCaptureDevice.default(.builtInWideAngleCamera, for: .video, position: position) {
            return device
        }

        // Fallback to any camera in that position using AVCaptureDeviceDiscoverySession
        let discoverySession = AVCaptureDevice.DiscoverySession(
            deviceTypes: [.builtInWideAngleCamera, .builtInTelephotoCamera, .builtInUltraWideCamera],
            mediaType: .video,
            position: position
        )
        return discoverySession.devices.first
    }
}

// MARK: - Photo Capture Delegate

extension CameraController: AVCapturePhotoCaptureDelegate {
    nonisolated func photoOutput(
        _ output: AVCapturePhotoOutput,
        didFinishProcessingPhoto photo: AVCapturePhoto,
        error: Error?
    ) {
        if let error = error {
            print("❌ Photo capture error: \(error)")
            return
        }

        guard let imageData = photo.fileDataRepresentation(),
              let image = UIImage(data: imageData) else {
            print("❌ Failed to create image from photo data")
            return
        }

        // Call completion on main actor
        Task { @MainActor in
            self.captureCompletion?(image)
            self.captureCompletion = nil
        }
    }
}

// MARK: - Camera Location Manager

/// Lightweight location manager to request permission when camera opens
/// This ensures location is available when the photo is captured
@MainActor
class CameraLocationManager: NSObject, ObservableObject, CLLocationManagerDelegate {
    private let manager = CLLocationManager()

    /// Current location (if available)
    @Published var location: CLLocation?
    private var pendingContinuations: [CheckedContinuation<CLLocation?, Never>] = []
    private var timeoutTask: Task<Void, Never>?
    private var isRequestingLocation = false

    override init() {
        super.init()
        manager.delegate = self
        manager.desiredAccuracy = kCLLocationAccuracyBest
    }

    func requestPermissionIfNeeded(promptIfNeeded: Bool = true) {
        let status = manager.authorizationStatus
        if status == .notDetermined {
            if promptIfNeeded {
                manager.requestWhenInUseAuthorization()
            }
        } else if status == .authorizedWhenInUse || status == .authorizedAlways {
            manager.startUpdatingLocation()
        }
    }

    /// Await a location update with a timeout (returns nil if not authorized or timed out).
    func awaitCurrentLocation(timeout: TimeInterval) async -> CLLocation? {
        let start = Date()
        var status = manager.authorizationStatus

        if status == .notDetermined {
            manager.requestWhenInUseAuthorization()
            while status == .notDetermined,
                  Date().timeIntervalSince(start) < timeout {
                try? await Task.sleep(for: .milliseconds(150))
                status = manager.authorizationStatus
            }
        }

        guard status == .authorizedWhenInUse || status == .authorizedAlways else {
            return location
        }
        if let location = location, abs(location.timestamp.timeIntervalSinceNow) < 30 {
            return location
        }

        let elapsed = Date().timeIntervalSince(start)
        let remaining = max(0.1, timeout - elapsed)
        return await withCheckedContinuation { continuation in
            Task { @MainActor in
                enqueueContinuation(continuation, timeout: remaining)
            }
        }
    }

    @MainActor
    private func enqueueContinuation(_ continuation: CheckedContinuation<CLLocation?, Never>, timeout: TimeInterval) {
        pendingContinuations.append(continuation)

        guard !isRequestingLocation else { return }
        isRequestingLocation = true
        manager.startUpdatingLocation()

        timeoutTask?.cancel()
        timeoutTask = Task { @MainActor in
            try? await Task.sleep(for: .seconds(timeout))
            if !pendingContinuations.isEmpty {
                resolvePending(with: nil)
            }
        }
    }

    @MainActor
    private func resolvePending(with location: CLLocation?) {
        let continuations = pendingContinuations
        pendingContinuations.removeAll()
        isRequestingLocation = false
        timeoutTask?.cancel()
        timeoutTask = nil
        manager.stopUpdatingLocation()
        continuations.forEach { $0.resume(returning: location) }
    }

    nonisolated func locationManagerDidChangeAuthorization(_ manager: CLLocationManager) {
        Task { @MainActor in
            let status = manager.authorizationStatus
            if status == .authorizedWhenInUse || status == .authorizedAlways {
                manager.startUpdatingLocation()
            }
        }
    }

    nonisolated func locationManager(_ manager: CLLocationManager, didUpdateLocations locations: [CLLocation]) {
        Task { @MainActor in
            self.location = locations.last
            resolvePending(with: locations.last)
        }
    }

    nonisolated func locationManager(_ manager: CLLocationManager, didFailWithError error: Error) {
        print("❌ Location manager error: \(error.localizedDescription)")
        Task { @MainActor in
            resolvePending(with: nil)
        }
    }
}

